import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { cn } from "@/lib/utils";

export interface OnboardingSegment {
  pct: number;
  label?: string;
  fill: string;
  trackBg?: string;
  textClass?: string;
}

export interface OnboardingProgressProps {
  title?: string;
  percent: number;
  segments: OnboardingSegment[];
  className?: string;
}

function OnboardingProgress({
  title = "Onboarding",
  percent,
  segments,
  className,
}: OnboardingProgressProps) {
  return (
    <Card variant="elevated" className={cn("flex flex-col gap-4 p-5", className)}>
      <CardHeader
        className="p-0"
        action={<span className="text-2xl font-bold text-neutral-900">{percent}%</span>}
      >
        <CardTitle>{title}</CardTitle>
      </CardHeader>

      <CardContent className="grid grid-cols-3 gap-2 p-0">
        {segments.map((segment, i) => (
          <div key={i} className="flex flex-col gap-2">
            <span
              className={cn(
                "text-xs font-medium",
                segment.pct > 0 ? "text-neutral-900" : "text-neutral-400",
              )}
            >
              {segment.pct}%
            </span>
            <div
              className={cn(
                "relative flex h-12 items-center overflow-hidden rounded-full px-3",
                segment.trackBg ?? "bg-neutral-100",
              )}
            >
              <div
                className={cn("absolute inset-y-0 left-0 transition-all duration-500", segment.fill)}
                style={{ width: `${segment.pct}%` }}
              />
              {segment.label && (
                <span className={cn("relative text-xs font-medium", segment.textClass ?? "text-neutral-900")}>
                  {segment.label}
                </span>
              )}
            </div>
          </div>
        ))}
      </CardContent>
    </Card>
  );
}

export { OnboardingProgress };

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const cardVariants = cva("text-card-foreground transition-shadow", {
  variants: {
    variant: {
      default: "rounded-3xl border bg-card shadow-card",
      elevated: "rounded-3xl border bg-card shadow-card hover:shadow-card-md",
      dark: "rounded-3xl border border-white/5 bg-brand-ink text-card-dark-foreground shadow-card-dark",
      glass: "rounded-3xl border border-white/40 bg-white/60 backdrop-blur shadow-card",
    },
  },
  defaultVariants: { variant: "default" },
});

export interface CardProps
  extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof cardVariants> {}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, variant, ...props }, ref) => (
    <div ref={ref} className={cn(cardVariants({ variant }), className)} {...props} />
  ),
);
Card.displayName = "Card";

const CardHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & { action?: React.ReactNode }
>(({ className, action, children, ...props }, ref) => (
  <div ref={ref} className={cn("flex items-center justify-between p-5 pb-0", className)} {...props}>
    <div className="flex flex-col space-y-1.5">{children}</div>
    {action}
  </div>
));
CardHeader.displayName = "CardHeader";

const CardTitle = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("text-lg font-semibold leading-none tracking-tight", className)} {...props} />
  ),
);
CardTitle.displayName = "CardTitle";

const CardDescription = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("text-sm text-muted-foreground", className)} {...props} />
  ),
);
CardDescription.displayName = "CardDescription";

const CardContent = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("p-5 pt-0", className)} {...props} />
  ),
);
CardContent.displayName = "CardContent";

const CardFooter = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("flex items-center p-5 pt-0", className)} {...props} />
  ),
);
CardFooter.displayName = "CardFooter";

export { Card, CardHeader, CardFooter, CardTitle, CardDescription, CardContent, cardVariants };
